arguments.file_text:
namespace sv_b15e4c6587f748ae8d296407a895c9bf.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_b15e4c6587f748ae8d296407a895c9bf.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var channel in channels)
                {
                    <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(threadOpen ? "thread-visible" : "")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h2># @activeChannel.Name</h2>
                <p>@activeChannel.Description</p>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="HandleScrollAsync">
                @if (loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }

                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-row" @onmouseenter="() => hoveredMessageId = msg.Id"
                             @onmouseleave="() => hoveredMessageId = null">
                            <div class="message-content-wrapper">
                                <div class="message-meta">
                                    <span class="author">@msg.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-text">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-list">
                                        @foreach (var reaction in msg.Reactions)
                                        {
                                            <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                    @onclick="() => ToggleReactionAsync(msg.Id, reaction.Emoji)">
                                                @reaction.Emoji @reaction.Users.Count
                                            </button>
                                        }
                                    </div>
                                }

                                @{
                                    var summary = threadSummaries.GetValueOrDefault(msg.Id);
                                }
                                @if (summary is not null)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                        — last @FormatRelativeTime(summary.LastReplyAt)
                                    </button>
                                }
                            </div>

                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread" @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <div class="react-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😀 React
                                        </button>
                                        @if (emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMessageKeyDown"
                          placeholder="Type a message…" rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(newMessageText)"
                        @onclick="SendMessageAsync">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@threadRootMessage.Author</span>
                <span class="timestamp">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-messages" @ref="threadListRef">
                @if (threadMessages is not null)
                {
                    @foreach (var reply in threadMessages)
                    {
                        <div class="message-row thread-reply">
                            <div class="message-content-wrapper">
                                <div class="message-meta">
                                    <span class="author">@reply.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                                </div>
                                <div class="message-text">@reply.Content</div>

                                @if (reply.Reactions.Count > 0)
                                {
                                    <div class="reaction-list">
                                        @foreach (var reaction in reply.Reactions)
                                        {
                                            <button class="reaction-badge"
                                                    title="@string.Join(", ", reaction.Users)"
                                                    @onclick="() => ToggleReactionAsync(reply.Id, reaction.Emoji)">
                                                @reaction.Emoji @reaction.Users.Count
                                            </button>
                                        }
                                    </div>
                                }
                            </div>
                        </div>
                    }
                }
            </div>

            <div class="thread-input-area">
                <textarea @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="HandleThreadKeyDown"
                          placeholder="Reply in thread…" rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(threadReplyText)"
                        @onclick="SendThreadReplyAsync">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // Data
    private List<Channel>? channels;
    private List<Message>? messages;
    private List<Message>? threadMessages;
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    // State
    private int activeChannelId;
    private Channel? activeChannel;
    private int messageSkip;
    private bool loadingOlder;
    private bool allOlderLoaded;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private string newMessageText = string.Empty;
    private string threadReplyText = string.Empty;
    private bool threadOpen;
    private Message? threadRootMessage;

    // Element refs
    private ElementReference messageListRef;
    private ElementReference threadListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messageSkip = 0;
        allOlderLoaded = false;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messageSkip = messages.Count;
        await BuildThreadSummariesAsync();
        await ChatService.MarkChannelReadAsync(channel.Id);
        RefreshChannelUnread(channel.Id);
    }

    private void RefreshChannelUnread(int channelId)
    {
        if (channels is null) return;
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    // ── Messages ──

    private async Task HandleScrollAsync()
    {
        if (loadingOlder || allOlderLoaded || activeChannel is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messageSkip, PageSize);
        if (older.Count == 0)
        {
            allOlderLoaded = true;
        }
        else
        {
            messages = older.Concat(messages!).ToList();
            messageSkip += older.Count;
            await BuildThreadSummariesAsync();
        }

        loadingOlder = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages ??= new();
        messages.Add(sent);
        messageSkip++;
        newMessageText = string.Empty;

        await ScrollToBottomAsync(".message-list");
    }

    private async Task HandleMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Threads ──

    private async Task BuildThreadSummariesAsync()
    {
        if (messages is null) return;
        threadSummaries.Clear();

        // Identify root messages (those that have at least one reply referencing them)
        var rootIds = messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToHashSet();

        // Also include messages that aren't replies themselves but might be roots
        // by fetching thread data for messages with no ReplyToId that appear as roots
        foreach (var rootId in rootIds)
        {
            var replies = messages.Where(m => m.ReplyToId == rootId).ToList();
            if (replies.Count > 0)
            {
                threadSummaries[rootId] = new ThreadSummary(
                    rootId,
                    replies.Count,
                    replies.Max(r => r.SentAt));
            }
        }
    }

    private async Task OpenThreadAsync(Message rootMsg)
    {
        threadRootMessage = rootMsg;
        threadMessages = await ChatService.GetThreadAsync(rootMsg.Id);
        threadOpen = true;
        emojiPickerMessageId = null;

        await Task.Yield();
        await ScrollToBottomAsync(".thread-messages");
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadMessages ??= new();
        threadMessages.Add(reply);

        // Also add to the main message list and update summary
        messages?.Add(reply);
        messageSkip++;
        await BuildThreadSummariesAsync();

        threadReplyText = string.Empty;
        await ScrollToBottomAsync(".thread-messages");
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);
        await ReloadCurrentViewAsync();
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        await ReloadCurrentViewAsync();
    }

    private async Task ReloadCurrentViewAsync()
    {
        if (activeChannel is null) return;
        messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messageSkip > 0 ? messageSkip : PageSize);
        await BuildThreadSummariesAsync();

        if (threadOpen && threadRootMessage is not null)
        {
            threadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    // ── Helpers ──

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 10 => "just now",
            < 60 => $"{(int)diff.TotalSeconds}s ago",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length <= 50 ? desc : desc[..47] + "…";
    }

    private async Task ScrollToBottomAsync(string selector)
    {
        try
        {
            await JS.InvokeVoidAsync("eval",
                $"(() => {{ var el = document.querySelector('{selector}'); if (el) el.scrollTop = el.scrollHeight; }})()");
        }
        catch { /* element may not be rendered yet */ }
    }
}

