+        threadSummaries.Clear();
+
+        // Identify root messages (those that have at least one reply referencing them)
+        var rootIds = messages
+            .Where(m => m.ReplyToId is not null)
+            .Select(m => m.ReplyToId!.Value)
+            .Distinct()
+            .ToHashSet();
+
+        // Also include messages that aren't replies themselves but might be roots
+        // by fetching thread data for messages with no ReplyToId that appear as roots
+        foreach (var rootId in rootIds)
+        {
+            var replies = messages.Where(m => m.ReplyToId == rootId).ToList();
+            if (replies.Count > 0)
+            {
+                threadSummaries[rootId] = new ThreadSummary(
+                    rootId,
+                    replies.Count,
+                    replies.Max(r => r.SentAt));
+            }
+        }
+    }
+
+    private async Task OpenThreadAsync(Message rootMsg)
+    {
+        threadRootMessage = rootMsg;
+        threadMessages = await ChatService.GetThreadAsync(rootMsg.Id);
+        threadOpen = true;
+        emojiPickerMessageId = null;
+
+        await Task.Yield();
+        await ScrollToBottomAsync(".thread-messages");
+    }
+
+    private void CloseThread()
+    {
+        threadOpen = false;
+        threadRootMessage = null;
+        threadMessages = null;
+    }
+
+    private async Task SendThreadReplyAsync()
+    {
+        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;
+
+        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
+        threadMessages ??= new();
+        threadMessages.Add(reply);
+
+        // Also add to the main message list and update summary
+        messages?.Add(reply);
+        messageSkip++;
+        await BuildThreadSummariesAsync();
+
+        threadReplyText = string.Empty;
+        await ScrollToBottomAsync(".thread-messages");
+    }
+
+    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    // ── Reactions ──
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    private async Task AddReactionAsync(int messageId, string emoji)
+    {
+        emojiPickerMessageId = null;
+        await ChatService.AddReactionAsync(messageId, emoji);
+        await ReloadCurrentViewAsync();
+    }
+
+    private async Task ToggleReactionAsync(int messageId, string emoji)
+    {
+        await ChatService.AddReactionAsync(messageId, emoji);
+        await ReloadCurrentViewAsync();
+    }
+
+    private async Task ReloadCurrentViewAsync()
+    {
+        if (activeChannel is null) return;
+        messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messageSkip > 0 ? messageSkip : PageSize);
+        await BuildThreadSummariesAsync();
+
+        if (threadOpen && threadRootMessage is not null)
+        {
+            threadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
+        }
+    }
+
+    // ── Helpers ──
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
+
+        return diff.TotalSeconds switch
+        {
+            < 10 => "just now",
+            < 60 => $"{(int)diff.TotalSeconds}s ago",
+            < 3600 => $"{(int)diff.TotalMinutes} min ago",
+            < 86400 => $"{(int)diff.TotalHours}h ago",
+            < 604800 => $"{(int)diff.TotalDays}d ago",
+            _ => sentAt.ToString("MMM d, yyyy")
+        };
+    }
+
+    private static string TruncateDescription(string desc)
+    {
+        return desc.Length <= 50 ? desc : desc[..47] + "…";
+    }
+
+    private async Task ScrollToBottomAsync(string selector)
+    {
+        try
+        {
+            await JS.InvokeVoidAsync("eval",
+                $"(() => {{ var el = document.querySelector('{selector}'); if (el) el.scrollTop = el.scrollHeight; }})()");
+        }
+        catch { /* element may not be rendered yet */ }
+    }
+}
